    <g font-family="sans-serif">
      <text x="20" y="58" fill="#a1a1aa" font-size="13" font-weight="700">① ステーブルコイン時価総額:初の四半期減少</text>
      <line x1="40" y1="260" x2="670" y2="260" stroke="rgba(255,255,255,.15)" stroke-width="1"/>
      <text x="150" y="88" fill="#a1a1aa" font-size="13" font-weight="700" text-anchor="middle">6/28推定</text>
      <rect x="80" y="120" width="120" height="140" rx="5" fill="rgba(161,161,170,.22)" stroke="#a1a1aa"/>
